patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..27a3bac70055 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4528,6 +4528,17 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
     return new ICmpInst(PredOut, Op0, Op1);

+  // icmp pred (~X ^ Y), ~X  -->  icmp pred X, (X ^ Y)
+  // Because bitwise NOT reverses order for all comparison types:
+  //   ~(X^Y) pred ~X  <=>  X pred (X^Y)
+  Value *X;
+  if (match(Op1, m_Not(m_Value(X)))) {
+    // Op0 is (xor Op1, A) = (xor ~X, A) = ~X ^ Y where Y = A.
+    // We need Op0 to have one use for profitability (it will be replaced).
+    if (Op0->hasOneUse())
+      return new ICmpInst(Pred, X, IC.Builder.CreateXor(X, A));
+  }
+
   return nullptr;
 }

@@ -4827,7 +4838,24 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
                               ConstantExpr::getNeg(RHSC));
   }

-  if (Instruction * R = foldICmpXorXX(I, Q, *this))
+  // icmp pred (~X ^ Y), ~Z  -->  icmp swapped_pred (X ^ Y), Z
+  // Because bitwise NOT reverses order for all comparison types:
+  //   ~(X^Y) pred ~Z  <=>  Z pred (X^Y)
+  {
+    Value *X, *Y, *Z;
+    if (match(Op0, m_OneUse(m_c_Xor(m_Not(m_Value(X)), m_Value(Y)))) &&
+        match(Op1, m_Not(m_Value(Z)))) {
+      Value *NewXor = Builder.CreateXor(X, Y);
+      return new ICmpInst(I.getSwappedPredicate(), NewXor, Z);
+    }
+    if (match(Op0, m_Not(m_Value(Z))) &&
+        match(Op1, m_OneUse(m_c_Xor(m_Not(m_Value(X)), m_Value(Y))))) {
+      Value *NewXor = Builder.CreateXor(X, Y);
+      return new ICmpInst(Pred, NewXor, Z);
+    }
+  }
+
+  if (Instruction *R = foldICmpXorXX(I, Q, *this))
     return R;
   if (Instruction *R = foldICmpOrXX(I, Q, *this))
     return R;

